// Parse AI response into individual platform rows for DB insert
const aiResponse = items[0].json;
let content;
try {
  const text = aiResponse.choices[0].message.content;
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  content = JSON.parse(cleaned);
} catch (e) {
  content = {
    instagram: { caption: 'Check this out!', hashtags: ['#content'], alt_text: '' },
    tiktok: { caption: 'Check this out!', hashtags: ['#fyp'], alt_text: '' },
    youtube: { caption: 'Check this out!', hashtags: ['#shorts'], alt_text: '' },
    facebook: { caption: 'Check this out!', hashtags: [], alt_text: '' },
    whatsapp: { caption: 'Check this out!', hashtags: [], alt_text: '' }
  };
}

const uploadId = $node['Dashboard Upload Webhook'].json.body.uploadId || 'upload-' + Date.now();
const theme = $node['Dashboard Upload Webhook'].json.body.theme || 'General';

const rows = [];
for (const [platform, data] of Object.entries(content)) {
  rows.push({
    json: {
      upload_id: uploadId,
      platform: platform,
      caption: data.caption || '',
      hashtags: JSON.stringify(data.hashtags || []),
      alt_text: data.alt_text || theme,
      status: 'pending',
      created_at: new Date().toISOString()
    }
  });
}

return rows;
